mapper.update:

update fnd_job
   set deleted_flag         = #{deletedFlag,jdbcType=BIT},
       update_time          = #{updateTime,jdbcType=TIMESTAMP},
       update_by            = #{updateBy,jdbcType=BIGINT}
 where id = #{id,jdbcType=BIGINT}


update fnd_job
   set job_sequence = #{jobSequence,jdbcType=BIGINT},
       update_time  = #{updateTime,jdbcType=TIMESTAMP},
       update_by    = #{updateBy,jdbcType=BIGINT}
 where id = #{id,jdbcType=BIGINT}


update fnd_job
set job_sequence = job_sequence + 1
where deleted_flag = 0
  and job_sequence >= #{minSequence,jdbcType=BIGINT}
  and job_sequence < #{maxSequence,jdbcType=BIGINT}


update fnd_job
set job_sequence = job_sequence - 1
where deleted_flag = 0
  and job_sequence > #{minSequence,jdbcType=BIGINT}
  and job_sequence <= #{maxSequence,jdbcType=BIGINT}
